DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PCCmacros.pl", "contextCurrency.pl", "parserLinearRelation.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $name = randomPerson(); $initial = random(80,120,5); Context("Currency")->flags->set(trimTrailingZeros => 1); $start = Currency($initial); $rate = random(12,18); $speed = Currency($rate); $final = $initial + $rate*random(12,23); $end = Currency($final); Context("LinearRelation")->variables->are(n => 'Real'); $equation = LinearRelation("$initial + $rate n = $final");
############################################################ # Body ############################################################
BEGIN_PGML Read the scenario. Then write a complete sentence that defines a variable to use. Lastly, write an equation to model the scenario. There is no need to solve the equation.
For [$name]'s 8th birthday party, [$name->possessive] parents rented a venue that charges a flat fee of [`[$start]`] plus [`[$speed]`] per guest. Ultimately it cost [$name]'s parents [`[$end]\text{.}`] How many guests were there? Write an equation to model this scenario. There is no need to solve it.
[@KeyboardInstructions('Use [|n|]* as the variable.')@]**
[_]{$equation}{20}
END_PGML
